SourceCode.Declaration:
public class ETGRateCardMasterHelper
{
    AgreementLine        agreementLine;
    PurchAgreementHeader agreementHeader;
    FormDataSource       formDS;
    InventDim            inventDim;

}

Method.Source:
public static ETGRateCardMasterHelper construct()
{
    return new ETGRateCardMasterHelper();
}

public AgreementLine parmAgreementLine(AgreementLine _agreementLine = agreementLine)
{
    agreementLine = _agreementLine;

    return agreementLine;
}

public InventDim parmInventDim(InventDim _inventDim = inventDim)
{
    inventDim = _inventDim;

    return inventDim;
}

public FormDataSource parmFormDataSource(FormDataSource _formDS = formDS)
{
    formDS = _formDS;

    return formDS;
}

public void processPurchaseAgrrement()
{
    ETGRateCardMaster rateCardMaster;
    boolean recordsExists;

    if(!agreementLine)
    {
        throw Error("Error. Agreement details does not exists");
    }

    select firstonly RecId from rateCardMaster 
        where rateCardMaster.RefRecId == agreementLine.RecId
        && rateCardMaster.LineNumber == agreementLine.LineNumber;

    if(!rateCardMaster.RecId)
    {
        this.createLinesFromAgreement();
    }
}

public void createLinesFromAgreement()
{
    ETGRateCardMaster rateCardMaster;
    PurchAgreementHeader header;
    InventTable inventTable, inventTableAgreementLine;
    AgreementLineQuantityCommitment lineQtyCommittment;
    EcoResReleasedProductsWithVariants ecoResProductVariantPerCompanyView;
    InventDim InventDimLoc, InventDimLocOrig;

    inventTableAgreementLine = InventTable::find(agreementLine.ItemId);

    header = PurchAgreementHeader::find(agreementLine.Agreement);

    InventDimLocOrig = agreementLine.inventDim();

    lineQtyCommittment = AgreementLineQuantityCommitment::find(agreementLine.RecId);

    while select inventTable
        where 
             inventTable.DataAreaId == agreementLine.ItemDataAreaId
            && inventTable.ETGSubCommodity == inventTableAgreementLine.ETGSubCommodity
            && inventTable.ETGSubCommodity != ""
    {
        while select ecoResProductVariantPerCompanyView
            where ecoResProductVariantPerCompanyView.ItemId == inventTable.ItemId
                && ecoResProductVariantPerCompanyView.DataAreaId == curExt()
            join InventDimLoc
            where InventDimLoc.inventDimId == ecoResProductVariantPerCompanyView.InventDimId
        {
            if(InventDimLoc.configId == InventDimLocOrig.configId
                && InventDimLoc.InventColorId == InventDimLocOrig.InventColorId
                && InventDimLoc.InventSizeId == InventDimLocOrig.InventSizeId
                && InventDimLoc.InventStyleId == InventDimLocOrig.InventStyleId)
            {
                continue;
            }
            rateCardMaster.clear();
            rateCardMaster.RateCardId = NumberSeq::newGetNum(PurchParameters::numRefRateCardId()).num();
            rateCardMaster.ItemId = inventTable.ItemId;
            rateCardMaster.SubCommodity = inventTable.ETGSubCommodity;
            rateCardMaster.RefRecId = agreementLine.RecId;
            rateCardMaster.LineNumber = agreementLine.LineNumber;
            rateCardMaster.ProductName = inventTable.itemName();
            rateCardMaster.ModuleSalesPurch = ModuleSalesPurch::Purch;
            rateCardMaster.VendAccount = header.VendAccount;
            rateCardMaster.VendName = header.vendName();
            rateCardMaster.RetailVariantId = ecoResProductVariantPerCompanyView.ETGRetailVariantId;
            rateCardMaster.Price = lineQtyCommittment.PricePerUnit;
            rateCardMaster.Qty = lineQtyCommittment.CommitedQuantity;
            //grade
            rateCardMaster.configId = InventDimLoc.configId;
            //size
            rateCardMaster.InventSizeId = InventDimLoc.InventSizeId;
            //origin
            rateCardMaster.InventColorId = InventDimLoc.InventColorId;
            //brand
            rateCardMaster.InventStyleId = InventDimLoc.InventStyleId;
            rateCardMaster.insert();
        }
    }
}
